package com.example.oidc.service;

import com.example.oidc.config.OidcClientConfig;
import com.example.oidc.model.TokenResponse;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;
import java.util.Map;
import java.util.UUID;

@Service
public class OidcService {
    public static final String SESSION_STATE = "OIDC_STATE";
    public static final String SESSION_NONCE = "OIDC_NONCE";
    public static final String SESSION_USER = "OIDC_USER";

    private final OidcClientConfig config;
    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;

    public OidcService(OidcClientConfig config, ObjectMapper objectMapper) {
        this.config = config;
        this.objectMapper = objectMapper;
        this.restTemplate = new RestTemplate();
    }

    public String buildAuthorizationRedirect(HttpSession session) {
        String state = UUID.randomUUID().toString();
        String nonce = generateNonce();
        session.setAttribute(SESSION_STATE, state);
        session.setAttribute(SESSION_NONCE, nonce);

        return config.getAuthorizationUri()
                + "?response_type=code"
                + "&client_id=" + urlEncode(config.getClientId())
                + "&redirect_uri=" + urlEncode(config.getRedirectUri())
                + "&scope=" + urlEncode(config.getScope())
                + "&state=" + urlEncode(state)
                + "&nonce=" + urlEncode(nonce);
    }

    public TokenResponse exchangeCodeForTokens(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setBasicAuth(config.getClientId(), config.getClientSecret(), StandardCharsets.UTF_8);

        MultiValueMap<String, String> form = new LinkedMultiValueMap<>();
        form.add("grant_type", "authorization_code");
        form.add("code", code);
        form.add("redirect_uri", config.getRedirectUri());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(form, headers);
        ResponseEntity<TokenResponse> response = restTemplate.exchange(
                config.getTokenUri(),
                HttpMethod.POST,
                request,
                TokenResponse.class
        );

        return response.getBody();
    }

    public Map<String, Object> fetchUserInfo(String accessToken) {
        if (config.getUserInfoUri() == null || config.getUserInfoUri().isBlank()) {
            return Map.of();
        }

        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        HttpEntity<Void> request = new HttpEntity<>(headers);

        ResponseEntity<Map> response = restTemplate.exchange(
                config.getUserInfoUri(),
                HttpMethod.GET,
                request,
                Map.class
        );

        return response.getBody() == null ? Map.of() : response.getBody();
    }

    public Map<String, Object> parseIdTokenClaims(String idToken) {
        try {
            String[] parts = idToken.split("\\.");
            if (parts.length < 2) {
                throw new IllegalArgumentException("Invalid id_token");
            }
            byte[] payload = Base64.getUrlDecoder().decode(parts[1]);
            return objectMapper.readValue(payload, new TypeReference<>() {});
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse id_token", e);
        }
    }

    public void validateState(String state, HttpSession session) {
        Object expected = session.getAttribute(SESSION_STATE);
        if (expected == null || !expected.equals(state)) {
            throw new IllegalArgumentException("Invalid state");
        }
    }

    public void validateNonce(Map<String, Object> claims, HttpSession session) {
        Object expected = session.getAttribute(SESSION_NONCE);
        Object actual = claims.get("nonce");
        if (expected != null && actual != null && !expected.equals(actual.toString())) {
            throw new IllegalArgumentException("Invalid nonce");
        }
    }

    public Instant calculateExpiry(TokenResponse tokenResponse, Map<String, Object> idTokenClaims) {
        Object exp = idTokenClaims.get("exp");
        if (exp instanceof Number number) {
            return Instant.ofEpochSecond(number.longValue());
        }
        if (tokenResponse.getExpiresIn() != null) {
            return Instant.now().plusSeconds(tokenResponse.getExpiresIn());
        }
        return Instant.now().plusSeconds(3600);
    }

    private String generateNonce() {
        byte[] bytes = new byte[16];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private String urlEncode(String value) {
        return java.net.URLEncoder.encode(value, StandardCharsets.UTF_8);
    }
}

package com.example.oidc.controller;

import com.example.oidc.model.OidcSessionUser;
import com.example.oidc.model.TokenResponse;
import com.example.oidc.service.OidcService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import java.util.Map;

@Controller
public class OidcController {
    private final OidcService oidcService;

    public OidcController(OidcService oidcService) {
        this.oidcService = oidcService;
    }

    @GetMapping("/login")
    public String login(HttpSession session) {
        return "redirect:" + oidcService.buildAuthorizationRedirect(session);
    }

    @GetMapping("/oidc/callback")
    public String callback(@RequestParam("code") String code,
                           @RequestParam("state") String state,
                           HttpServletRequest request) {
        HttpSession session = request.getSession(true);

        oidcService.validateState(state, session);
        TokenResponse tokenResponse = oidcService.exchangeCodeForTokens(code);
        Map<String, Object> idTokenClaims = oidcService.parseIdTokenClaims(tokenResponse.getIdToken());
        oidcService.validateNonce(idTokenClaims, session);
        Map<String, Object> userInfo = oidcService.fetchUserInfo(tokenResponse.getAccessToken());

        OidcSessionUser user = new OidcSessionUser();
        user.setSubject(stringValue(idTokenClaims.get("sub")));
        user.setUsername(resolveUsername(idTokenClaims, userInfo));
        user.setEmail(resolveEmail(idTokenClaims, userInfo));
        user.setAccessToken(tokenResponse.getAccessToken());
        user.setIdToken(tokenResponse.getIdToken());
        user.setRefreshToken(tokenResponse.getRefreshToken());
        user.setExpiresAt(oidcService.calculateExpiry(tokenResponse, idTokenClaims));
        user.setIdTokenClaims(idTokenClaims);
        user.setUserInfoClaims(userInfo);

        session.setAttribute(OidcService.SESSION_USER, user);
        session.removeAttribute(OidcService.SESSION_STATE);
        session.removeAttribute(OidcService.SESSION_NONCE);

        return "redirect:/";
    }

    @GetMapping("/logout")
    public String logout(HttpSession session) {
        session.invalidate();
        return "redirect:/";
    }

    private String resolveUsername(Map<String, Object> idTokenClaims, Map<String, Object> userInfo) {
        String preferred = firstNonNull(
                stringValue(userInfo.get("preferred_username")),
                stringValue(idTokenClaims.get("preferred_username")),
                stringValue(userInfo.get("name")),
                stringValue(idTokenClaims.get("name")),
                stringValue(idTokenClaims.get("sub"))
        );
        return preferred;
    }

    private String resolveEmail(Map<String, Object> idTokenClaims, Map<String, Object> userInfo) {
        return firstNonNull(
                stringValue(userInfo.get("email")),
                stringValue(idTokenClaims.get("email"))
        );
    }

    private String firstNonNull(String... values) {
        for (String value : values) {
            if (value != null && !value.isBlank()) {
                return value;
            }
        }
        return null;
    }

    private String stringValue(Object value) {
        return value == null ? null : value.toString();
    }
}

package com.example.oidc.controller;

import com.example.oidc.model.OidcSessionUser;
import com.example.oidc.service.OidcService;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class HomeController {

    @GetMapping("/")
    public ResponseEntity<Map<String, Object>> home(HttpSession session) {
        OidcSessionUser user = (OidcSessionUser) session.getAttribute(OidcService.SESSION_USER);

        Map<String, Object> body = new LinkedHashMap<>();
        body.put("authenticated", user != null);

        if (user != null) {
            body.put("subject", user.getSubject());
            body.put("username", user.getUsername());
            body.put("email", user.getEmail());
            body.put("expiresAt", user.getExpiresAt());
            body.put("idTokenClaims", user.getIdTokenClaims());
            body.put("userInfoClaims", user.getUserInfoClaims());
        } else {
            body.put("loginUrl", "/login");
        }

        return ResponseEntity.ok(body);
    }
}

package com.example.oidc.config;

import com.example.oidc.service.OidcService;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.core.authority.AuthorityUtils;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;

@Configuration
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(Customizer.withDefaults())
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/", "/login", "/oidc/callback", "/logout", "/error").permitAll()
                        .anyRequest().authenticated()
                )
                .addFilterAfter(sessionAuthenticationFilter(), org.springframework.security.web.authentication.AnonymousAuthenticationFilter.class);

        return http.build();
    }

    @Bean
    public OncePerRequestFilter sessionAuthenticationFilter() {
        return new OncePerRequestFilter() {
            @Override
            protected void doFilterInternal(HttpServletRequest request,
                                            HttpServletResponse response,
                                            FilterChain filterChain) throws ServletException, IOException {
                HttpSession session = request.getSession(false);
                if (session != null && SecurityContextHolder.getContext().getAuthentication() == null) {
                    Object principal = session.getAttribute(OidcService.SESSION_USER);
                    if (principal != null) {
                        AbstractAuthenticationToken authentication = new AbstractAuthenticationToken(
                                AuthorityUtils.createAuthorityList("ROLE_USER")) {
                            @Override
                            public Object getCredentials() {
                                return "";
                            }

                            @Override
                            public Object getPrincipal() {
                                return principal;
                            }
                        };
                        authentication.setAuthenticated(true);
                        SecurityContextHolder.getContext().setAuthentication(authentication);
                    }
                }
                filterChain.doFilter(request, response);
            }
        };
    }
}

package com.example.oidc.controller;

import com.example.oidc.model.OidcSessionUser;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class ProfileController {

    @GetMapping("/profile")
    public OidcSessionUser profile(Authentication authentication, HttpSession session) {
        if (authentication != null && authentication.getPrincipal() instanceof OidcSessionUser user) {
            return user;
        }
        return (OidcSessionUser) session.getAttribute("OIDC_USER");
    }
}

